/**
 * Instance-discovery filter for SQLServer:Databases perf counter instances.
 * Input: a database name returned by PDH.ObjectInstances("SQLServer:Databases").
 * Returns a NetXMS instance-filter result: %(accepted, instanceKey, displayName).
 *
 * Skips the "_Total" pseudo-instance (server-wide aggregate is collected by separate
 * static DCIs in this template) and accepts every real database.
 */
function filterMssqlDatabase(database)
{
   if (database == "_Total")
      return false;

   return %(true, database, database);
}
